import { useState } from "react";

const BG_IMG   = "data:image/jpeg;base64,";
const LOGO_IMG = "data:image/png;base64,";

export default function LoginSaluDigital() {
  const [usuario, setUsuario]       = useState("");
  const [contrasena, setContrasena] = useState("");
  const [error, setError]           = useState("");
  const [loading, setLoading]       = useState(false);

  const handleLogin = () => {
    if (!usuario || !contrasena) {
      setError("Complete usuario y contraseña.");
      return;
    }
    setLoading(true);
    setError("");
    // Simula validación
    setTimeout(() => {
      setLoading(false);
      setError("Credenciales incorrectas. Intente de nuevo.");
    }, 1000);
  };

  return (
    <div
      className="min-h-screen flex flex-col items-center justify-center"
      style={{ backgroundColor: "#00003a" }}
    >
      {/* Card principal */}
      <div
        className="w-full max-w-4xl mx-4 rounded-xl shadow-2xl overflow-hidden flex flex-col md:flex-row"
        style={{ border: "3px solid #E67E22", minHeight: 420 }}
      >
        {/* ── MITAD IZQUIERDA ── */}
        <div className="relative flex-1 flex items-center justify-center min-h-64 md:min-h-0">
          {/* Imagen de fondo */}
          <img
            src={BG_IMG}
            alt="UNELLEZ"
            className="absolute inset-0 w-full h-full object-cover"
          />
          {/* Overlay semitransparente */}
          <div
            className="absolute inset-0"
            style={{ background: "linear-gradient(135deg, rgba(0,0,60,0.45) 0%, rgba(0,0,80,0.35) 100%)" }}
          />
          {/* Texto bienvenida */}
          <div className="relative z-10 px-10 py-8">
            <h1
              className="text-white font-black leading-tight drop-shadow-lg"
              style={{ fontSize: "2.6rem", textShadow: "0 2px 12px rgba(0,0,0,0.7)" }}
            >
              ¡BIENVENIDO!
            </h1>
            <p
              className="text-white font-bold mt-3 leading-relaxed drop-shadow-md"
              style={{ fontSize: "1.45rem", textShadow: "0 2px 8px rgba(0,0,0,0.6)" }}
            >
              Sistema SaluDigital<br />UNELLEZ
            </p>
          </div>
        </div>

        {/* ── MITAD DERECHA ── */}
        <div
          className="relative flex-1 flex flex-col items-center justify-center px-10 py-8"
          style={{ backgroundColor: "rgba(0,0,60,0.92)" }}
        >
          {/* Imagen desenfocada de fondo lado derecho */}
          <img
            src={BG_IMG}
            alt=""
            className="absolute inset-0 w-full h-full object-cover opacity-20"
            style={{ filter: "blur(8px)", transform: "scale(1.1)" }}
          />

          <div className="relative z-10 w-full max-w-xs flex flex-col items-center gap-6">
            {/* Logo */}
            <img
              src={LOGO_IMG}
              alt="Logo UNELLEZ"
              className="rounded-full shadow-lg"
              style={{ width: 130, height: 130, objectFit: "cover", border: "3px solid #E67E22" }}
            />

            {/* Campo Usuario */}
            <div className="w-full">
              <input
                type="text"
                placeholder="Usuario"
                value={usuario}
                onChange={e => setUsuario(e.target.value)}
                onKeyDown={e => e.key === "Enter" && handleLogin()}
                className="w-full bg-transparent text-white placeholder-gray-300 text-base pb-1 outline-none"
                style={{ borderBottom: "2px solid white", caretColor: "white" }}
              />
            </div>

            {/* Campo Contraseña */}
            <div className="w-full">
              <input
                type="password"
                placeholder="Contraseña"
                value={contrasena}
                onChange={e => setContrasena(e.target.value)}
                onKeyDown={e => e.key === "Enter" && handleLogin()}
                className="w-full bg-transparent text-white placeholder-gray-300 text-base pb-1 outline-none"
                style={{ borderBottom: "2px solid white", caretColor: "white" }}
              />
            </div>

            {/* Error */}
            {error && (
              <p className="text-red-400 text-sm text-center w-full -mt-2">
                {error}
              </p>
            )}

            {/* Botón Ingresar */}
            <button
              onClick={handleLogin}
              disabled={loading}
              className="w-full font-bold text-base py-3 rounded-2xl shadow-lg transition-all duration-200"
              style={{
                background: loading ? "#ccc" : "white",
                color: "#E67E22",
                letterSpacing: "0.08em",
                cursor: loading ? "not-allowed" : "pointer",
              }}
            >
              {loading ? "VERIFICANDO..." : "INGRESAR"}
            </button>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="mt-6 text-center">
        <p className="text-white text-sm opacity-80">
          Desarrollado por: Kaira Henao y José Marcano - 2026
        </p>
      </div>
    </div>
  );
}
